import type { Page, Locator } from '@playwright/test'

export class BasePage {
  readonly page: Page

  constructor(page: Page) {
    this.page = page
  }

  async goto(route: string) {
    if (!route || route.trim() === '') {
      throw new Error(`Invalid route: "${route}" must be a non-empty string.`)
    }
    try {
      await this.page.goto(route)
      await this.page.waitForLoadState('domcontentloaded')
    } catch (error) {
      throw new Error(`Failed to navigate to "${route}": ${error instanceof Error ? error.message : String(error)}`)
    }
  }

  async navigateTo(label: string) {
    const links = this.page.getByRole('link', { name: label })
    const count = await links.count()
    if (count === 0) {
      throw new Error(`No link found with name "${label}".`)
    }
    if (count > 1) {
      throw new Error(`Ambiguous link "${label}": ${count} matches found. Use a more specific selector.`)
    }
    try {
      await links.first().click()
      await this.page.waitForLoadState('domcontentloaded')
    } catch (error) {
      throw new Error(`Failed to navigate via link "${label}": ${error instanceof Error ? error.message : String(error)}`)
    }
  }

  getHeading(text: string): Locator {
    return this.page.getByRole('heading', { name: text })
  }

  getToast(text: string): Locator {
    return this.page.locator('[data-sonner-toast]').getByText(text)
  }

  async clearState() {
    try {
      await this.page.goto('/')
      await this.page.evaluate(() => {
        localStorage.clear()
        sessionStorage.clear()
      })
      await this.page.context().clearCookies()
      await this.page.reload()
      await this.page.waitForLoadState('domcontentloaded')
    } catch (error) {
      const url = this.page.url()
      throw new Error(
        `clearState failed at "${url}": ${error instanceof Error ? error.message : String(error)}`
      )
    }
  }
}



import type { Locator } from '@playwright/test'
import { expect } from '@playwright/test'
import { BasePage } from './base-page'

interface CadastroFormData {
  nome: string
  cpfCnpj: string
  email: string
  telefone: string
  cep: string
  logradouro: string
  numero: string
  bairro: string
  cidade: string
  uf: string
}

export class CadastroPage extends BasePage {
  readonly heading: Locator
  readonly nomeInput: Locator
  readonly cpfCnpjInput: Locator
  readonly emailInput: Locator
  readonly telefoneInput: Locator
  readonly cepInput: Locator
  readonly logradouroInput: Locator
  readonly numeroInput: Locator
  readonly bairroInput: Locator
  readonly cidadeInput: Locator
  readonly ufCombobox: Locator
  readonly submitButton: Locator

  constructor(page: import('@playwright/test').Page) {
    super(page)
    this.heading = this.getHeading('Cadastro')
    this.nomeInput = page.getByLabel('Nome Completo')
    this.cpfCnpjInput = page.getByLabel('CPF/CNPJ')
    this.emailInput = page.getByLabel('E-mail')
    this.telefoneInput = page.getByLabel('Telefone')
    this.cepInput = page.getByLabel('CEP')
    this.logradouroInput = page.getByLabel('Logradouro')
    this.numeroInput = page.getByLabel('Numero')
    this.bairroInput = page.getByLabel('Bairro')
    this.cidadeInput = page.getByLabel('Cidade')
    this.ufCombobox = page.getByRole('combobox', { name: 'UF' })
    this.submitButton = page.getByRole('button', { name: 'Salvar', exact: true })
  }

  async goto() {
    await super.goto('/cadastro')
  }

  async fillForm(data: CadastroFormData) {
    await this.nomeInput.fill(data.nome)
    await this.cpfCnpjInput.fill(data.cpfCnpj)
    await this.emailInput.fill(data.email)
    await this.telefoneInput.fill(data.telefone)
    await this.cepInput.fill(data.cep)
    await this.logradouroInput.fill(data.logradouro)
    await this.numeroInput.fill(data.numero)
    await this.bairroInput.fill(data.bairro)
    await this.cidadeInput.fill(data.cidade)
    await this.ufCombobox.click()
    await this.page.getByRole('option', { name: data.uf }).click()
  }

  async submit() {
    await this.submitButton.click()
  }

  async expectFormCleared() {
    await expect(this.nomeInput).toHaveValue('')
    await expect(this.cpfCnpjInput).toHaveValue('')
  }
}



import type { Page, Locator } from '@playwright/test'
import { BasePage } from './base-page'

export class DocumentosPage extends BasePage {
  // Locators
  readonly heading: Locator
  readonly searchInput: Locator
  readonly tipoFilter: Locator
  readonly statusFilter: Locator
  readonly novoDocumentoButton: Locator
  readonly clearFiltersButton: Locator
  readonly dataTable: Locator
  readonly deleteDialog: Locator
  readonly viewDialog: Locator

  constructor(page: Page) {
    super(page)
    this.heading = this.getHeading('Documentos')
    this.searchInput = page.getByPlaceholder('Buscar por numero, titulo, assunto ou destinatario...')
    this.tipoFilter = page.getByRole('combobox', { name: 'Tipo' })
    this.statusFilter = page.getByRole('combobox', { name: 'Status' })
    this.novoDocumentoButton = page.getByRole('button', { name: 'Novo Documento' })
    this.clearFiltersButton = page.getByRole('button', { name: 'Limpar' })
    this.dataTable = page.getByRole('table')
    this.deleteDialog = page.getByRole('alertdialog', { name: 'Excluir Documento' })
    this.viewDialog = page.getByRole('dialog').filter({ hasText: 'Visualizacao do documento' })
  }

  async goto() {
    await super.goto('/documentos')
  }

  async search(text: string) {
    await this.searchInput.fill(text)
  }

  async filterByTipo(tipo: string) {
    await this.tipoFilter.click()
    await this.page.getByRole('option', { name: tipo }).click()
  }

  async filterByStatus(status: string) {
    await this.statusFilter.click()
    await this.page.getByRole('option', { name: status }).click()
  }

  async clearFilters() {
    await this.clearFiltersButton.click()
  }

  findRowByText(text: string): Locator {
    return this.dataTable.getByRole('row').filter({ hasText: text })
  }

  async viewRowByText(text: string) {
    const row = this.findRowByText(text).first()
    await row.getByRole('button', { name: 'Visualizar' }).click()
  }

  async deleteRowByText(text: string) {
    const row = this.findRowByText(text).first()
    await row.getByRole('button', { name: 'Excluir' }).click()
  }

  async confirmDelete() {
    await this.deleteDialog.getByRole('button', { name: 'Excluir' }).click()
  }

  async cancelDelete() {
    await this.deleteDialog.getByRole('button', { name: 'Cancelar' }).click()
  }
}



