import { test, expect } from '@playwright/test'
import { DocumentosPage } from './pages/documentos-page'

const SEED_ROW_COUNT = 4 // 3 data rows + 1 header row

test.describe('Documentos', () => {
  let pageObj: DocumentosPage

  test.beforeEach(async ({ page }) => {
    pageObj = new DocumentosPage(page)
    await pageObj.clearState()
    await pageObj.goto()
  })

  test('should render page with header and table', async () => {
    await expect(pageObj.heading).toBeVisible()
    await expect(pageObj.page.getByText('Gerencie ofícios, memorandos e outros documentos')).toBeVisible()
    await expect(pageObj.novoDocumentoButton).toBeVisible()
    await expect(pageObj.dataTable).toBeVisible()
    await expect(pageObj.dataTable.getByRole('row')).toHaveCount(SEED_ROW_COUNT)
  })

  test('should search documents by text', async () => {
    await pageObj.search('OF-001')
    await expect(pageObj.dataTable.getByRole('row')).toHaveCount(2) // 1 data + 1 header

    await pageObj.search('')
    await expect(pageObj.dataTable.getByRole('row')).toHaveCount(SEED_ROW_COUNT)

    await pageObj.search('Secretaria')
    await expect(pageObj.dataTable.getByRole('row')).toHaveCount(2)
  })

  test('should filter by Tipo', async () => {
    await pageObj.filterByTipo('Memorando')
    await expect(pageObj.dataTable.getByRole('row')).toHaveCount(2)

    await pageObj.filterByTipo('Ofício')
    await expect(pageObj.dataTable.getByRole('row')).toHaveCount(2)
  })

  test('should filter by Status', async () => {
    await pageObj.filterByStatus('Finalizado')
    await expect(pageObj.dataTable.getByRole('row')).toHaveCount(2)

    await pageObj.filterByStatus('Enviado')
    await expect(pageObj.dataTable.getByRole('row')).toHaveCount(2)

    await pageObj.filterByStatus('Arquivado')
    await expect(pageObj.dataTable.getByRole('row')).toHaveCount(2)
  })

  test('should clear filters', async () => {
    await pageObj.search('OF-001')
    await expect(pageObj.clearFiltersButton).toBeVisible()

    await pageObj.clearFilters()
    await expect(pageObj.searchInput).toHaveValue('')
    await expect(pageObj.tipoFilter).toContainText('Tipo')
    await expect(pageObj.statusFilter).toContainText('Status')
    await expect(pageObj.dataTable.getByRole('row')).toHaveCount(SEED_ROW_COUNT)
  })

  test('should view document details in dialog', async () => {
    await pageObj.viewRowByText('OF-001/2024')
    await expect(pageObj.viewDialog).toBeVisible()
    await expect(pageObj.viewDialog.getByRole('heading')).toContainText('OF-001/2024')
    await expect(pageObj.viewDialog.getByRole('heading')).toContainText('Ofício de Comunicação')
  })

  test('should delete document with confirmation', async () => {
    await expect(pageObj.dataTable.getByRole('row')).toHaveCount(SEED_ROW_COUNT)

    await pageObj.deleteRowByText('OF-001/2024')
    await expect(pageObj.deleteDialog).toBeVisible()
    await pageObj.confirmDelete()

    await expect(pageObj.getToast('Documento excluído com sucesso!')).toBeVisible()
    await expect(pageObj.dataTable.getByRole('row')).toHaveCount(SEED_ROW_COUNT - 1)
  })

  test('should cancel delete operation', async () => {
    await expect(pageObj.dataTable.getByRole('row')).toHaveCount(SEED_ROW_COUNT)

    await pageObj.deleteRowByText('OF-001/2024')
    await expect(pageObj.deleteDialog).toBeVisible()
    await pageObj.cancelDelete()

    await expect(pageObj.deleteDialog).not.toBeVisible()
    await expect(pageObj.dataTable.getByRole('row')).toHaveCount(SEED_ROW_COUNT)
  })
})



import { test, expect } from '@playwright/test'
import { SolicitacoesPage } from './pages/solicitacoes-page'

const SEED_ROW_COUNT = 4 // 3 data rows + 1 header row
const EXPECTED_FILTERED_COUNT = 2 // 1 data row + 1 header row
const SEED_TITLE = 'Solicitação de Férias'
const SEED_NAME = 'Maria Silva Santos'

test.describe('Solicitações', () => {
  let pageObj: SolicitacoesPage

  test.beforeEach(async ({ page }) => {
    pageObj = new SolicitacoesPage(page)
    await pageObj.clearState()
    await pageObj.goto()
  })

  test('should render page with header and table', async () => {
    await expect(pageObj.heading).toBeVisible()
    await expect(pageObj.page.getByText('Gerencie solicitações e demandas')).toBeVisible()
    await expect(pageObj.novaSolicitacaoButton).toBeVisible()
    await expect(pageObj.dataTable).toBeVisible()
    await expect(pageObj.dataTable.getByRole('row')).toHaveCount(SEED_ROW_COUNT)
  })

  test('should search solicitações by text', async () => {
    await pageObj.search('Férias')
    await expect(pageObj.dataTable.getByRole('row')).toHaveCount(EXPECTED_FILTERED_COUNT)

    await pageObj.search('')
    await expect(pageObj.dataTable.getByRole('row')).toHaveCount(SEED_ROW_COUNT)

    await pageObj.search('Tech Solutions')
    await expect(pageObj.dataTable.getByRole('row')).toHaveCount(EXPECTED_FILTERED_COUNT)
  })

  test('should filter by Status', async () => {
    await pageObj.filterByStatus('Pendente')
    await expect(pageObj.dataTable.getByRole('row')).toHaveCount(EXPECTED_FILTERED_COUNT)

    await pageObj.filterByStatus('Em Análise')
    await expect(pageObj.dataTable.getByRole('row')).toHaveCount(EXPECTED_FILTERED_COUNT)

    await pageObj.filterByStatus('Aprovada')
    await expect(pageObj.dataTable.getByRole('row')).toHaveCount(EXPECTED_FILTERED_COUNT)
  })

  test('should filter by Prioridade', async () => {
    await pageObj.filterByPrioridade('Média')
    await expect(pageObj.dataTable.getByRole('row')).toHaveCount(EXPECTED_FILTERED_COUNT)

    await pageObj.filterByPrioridade('Alta')
    await expect(pageObj.dataTable.getByRole('row')).toHaveCount(EXPECTED_FILTERED_COUNT)

    await pageObj.filterByPrioridade('Urgente')
    await expect(pageObj.dataTable.getByRole('row')).toHaveCount(EXPECTED_FILTERED_COUNT)
  })

  test('should clear filters', async () => {
    await pageObj.search('Férias')
    await expect(pageObj.clearFiltersButton).toBeVisible()

    await pageObj.clearFilters()
    await expect(pageObj.searchInput).toHaveValue('')
    await expect(pageObj.statusFilter).toContainText('Status')
    await expect(pageObj.prioridadeFilter).toContainText('Prioridade')
    await expect(pageObj.dataTable.getByRole('row')).toHaveCount(SEED_ROW_COUNT)
  })

  test('should view solicitation details in dialog', async () => {
    await pageObj.viewRowByText(SEED_TITLE)
    await expect(pageObj.viewDialog).toBeVisible()
    await expect(pageObj.viewDialog.getByRole('heading', { name: SEED_TITLE })).toBeVisible()
    await expect(pageObj.viewDialog.getByText(SEED_NAME)).toBeVisible()
  })

  test('should delete solicitação with confirmation', async () => {
    await expect(pageObj.dataTable.getByRole('row')).toHaveCount(SEED_ROW_COUNT)

    await pageObj.deleteRowByText(SEED_TITLE)
    await expect(pageObj.deleteDialog).toBeVisible()
    await pageObj.confirmDelete()

    await expect(pageObj.getToast('Solicitação excluída com sucesso!')).toBeVisible()
    await expect(pageObj.dataTable.getByRole('row')).toHaveCount(SEED_ROW_COUNT - 1)
  })

  test('should cancel delete operation', async () => {
    await expect(pageObj.dataTable.getByRole('row')).toHaveCount(SEED_ROW_COUNT)

    await pageObj.deleteRowByText(SEED_TITLE)
    await expect(pageObj.deleteDialog).toBeVisible()
    await pageObj.cancelDelete()

    await expect(pageObj.deleteDialog).not.toBeVisible()
    await expect(pageObj.dataTable.getByRole('row')).toHaveCount(SEED_ROW_COUNT)
  })
})



# GEMINI.md - Sistema Interno de Gestão Integrada

Este documento fornece orientações e contexto sobre o projeto **v0-sistema-interno-web**, um sistema de gestão interna robusto e moderno.

## Visão Geral do Projeto

O sistema é uma aplicação web de gestão integrada que permite o gerenciamento de cadastros (pessoas e empresas), solicitações (fluxos de trabalho) e documentos oficiais. Ele foi desenvolvido com foco em performance, acessibilidade e experiência do usuário (UX).

### Tecnologias Principais
- **Framework:** Next.js (App Router)
- **Linguagem:** TypeScript
- **Estilização:** Tailwind CSS v4 + PostCSS
- **Componentes UI:** Radix UI (base para padrões Shadcn UI)
- **Gerenciamento de Estado:** Zustand (com persistência local)
- **Validação e Tipagem:** Zod + Custom Hooks
- **Ícones:** Lucide React
- **Gráficos:** Recharts

## Arquitetura e Estrutura de Pastas

O projeto segue uma estrutura modular e escalável:

- `app/`: Contém as rotas e layouts da aplicação (Dashboard, Cadastro, Solicitações, Documentos, Configurações).
- `components/`: Organizado por domínios de UI:
    - `ui/`: Componentes base reutilizáveis (botões, inputs, cards, etc.).
    - `layout/`: Componentes de estrutura (AppShell, Sidebar, Header).
    - `forms/`: Componentes especializados para formulários.
    - `feedback/`: Alertas, badges de status, diálogos de confirmação e estados de carregamento.
    - `data/`: Tabelas e visualização de dados.
- `store/`: Gerenciamento de estado global via Zustand (`useAppStore`).
- `lib/`: Utilitários (`utils.ts`), constantes globais (`constants.ts`), tipos TypeScript (`types.ts`) e esquemas de validação (`validations.ts`).
- `hooks/`: Hooks personalizados para lógica de negócio reutilizável (`use-validation`, `use-debounce`).
- `services/`: Camada de abstração para serviços externos ou persistência (`storage.ts`).

## Comandos Principais

Utilize os comandos abaixo para gerenciar o ciclo de vida do projeto:

| Comando | Descrição |
|---------|-----------|
| `npm run dev` | Inicia o servidor de desenvolvimento em `localhost:3000`. |
| `npm run build` | Compila a aplicação para produção. |
| `npm run start` | Inicia o servidor de produção após o build. |
| `npm run lint` | Executa a verificação estática do código com ESLint. |

## Convenções de Desenvolvimento

- **Nomenclatura:** 
    - Arquivos e pastas: `kebab-case`.
    - Componentes React: `PascalCase`.
    - Funções e variáveis: `camelCase`.
- **Componentes:** Prefira a criação de componentes pequenos e especializados. Utilize os componentes em `@/components/ui` como base.
- **Estado Global:** O `useAppStore` centraliza os dados principais. Para estados locais de formulários, utilize hooks de estado ou bibliotecas de formulário.
- **Validação:** Sempre utilize Zod para definir schemas de dados e os hooks de validação existentes para garantir a integridade dos dados inseridos.
- **Estilização:** Utilize classes utilitárias do Tailwind CSS. Evite CSS arbitrário fora do `globals.css`.

## Fluxos de Trabalho Implementados

1. **Auto-Save:** O sistema possui um mecanismo de rascunho automático em formulários de cadastro para evitar perda de dados.
2. **Persistência:** Dados simulados e alterações do usuário são persistidos no `localStorage` via Zustand.
3. **Feedback:** Todas as ações críticas (salvar, excluir) fornecem feedback visual imediato via `sonner` (toasts) e diálogos de confirmação.



