function FieldError({
  className,
  children,
  errors,
  ...props
}: React.ComponentProps<'div'> & {
  errors?: Array<{ message?: string } | undefined>
}) {
  const content = useMemo(() => {
    if (children) {
      return children
    }

    if (!errors) {
      return null
    }

    if (errors.length === 1 && errors[0]?.message) {
      return errors[0].message
    }

    return (

        {errors.map(
          (error, index) =>
            error?.message && 
{error.message},
        )}

    )
  }, [children, errors])

  if (!content) {
    return null
  }

  return (


      {content}

  )
}

