  // Dados Principais
  nome: string
  cpfCnpj: string
  tipo: 'pessoa_fisica' | 'pessoa_juridica'

  // Contato
  email: string
  telefone: string

  // Endereço
  cep: string
  logradouro: string
  numero: string
  complemento?: string
  bairro: string
  cidade: string
  uf: string

  // Observações
  observacoes?: string

  // Status
  status: 'ativo' | 'inativo' | 'pendente'
}

