export interface Documento extends BaseEntity {
  numero: string
  tipo: TipoDocumento
  titulo: string
  conteudo: string
  destinatario: string
  remetente: string
  assunto: string
  dataDocumento: string
  status: 'rascunho' | 'finalizado' | 'enviado' | 'arquivado'
  anexos?: string[]
}

export type DocumentoForm = Omit

