  perfil: {
    nome: string
    email: string
    cargo: string
    setor: string
    avatar?: string
  }
  tema: 'light' | 'dark' | 'system'
  notificacoes: {
    email: boolean
    push: boolean
    sms: boolean
  }
  idioma: 'pt-BR' | 'en-US' | 'es-ES'
}

