import { clsx, type ClassValue } from 'clsx'
import { twMerge } from 'tailwind-merge'

export function cn(...inputs: ClassValue[]) {
  return twMerge(clsx(inputs))
}



import type { ValidationResult, ValidationError } from './types'

// ===== TIPOS DE VALIDAÇÃO =====

export type ValidationRule = {
  validate: (value: T, formData?: Record) => boolean
  message: string
}

// ===== REGRAS DE VALIDAÇÃO =====

export const required = (message = 'Este campo e obrigatorio'): ValidationRule => ({
  validate: (value) => {
    if (typeof value === 'string') return value.trim().length > 0
    return value !== null && value !== undefined
  },
  message,
})

export const minLength = (min: number, message?: string): ValidationRule => ({
  validate: (value) => typeof value === 'string' && value.length >= min,
  message: message || `Minimo de ${min} caracteres`,
})

export const maxLength = (max: number, message?: string): ValidationRule => ({
  validate: (value) => typeof value === 'string' && value.length <= max,
  message: message || `Maximo de ${max} caracteres`,
})

export const email = (message = 'E-mail invalido'): ValidationRule => ({
  validate: (value) => {
    if (!value || typeof value !== 'string') return false
    const emailRegex = /^[^\s@]+@[^\s@]+\.[^\s@]+$/
    return emailRegex.test(value)
  },
  message,
})

export const cpf = (message = 'CPF invalido'): ValidationRule => ({
  validate: (value) => {
    if (!value || typeof value !== 'string') return false
    const cpfClean = value.replace(/\D/g, '')
    if (cpfClean.length !== 11) return false

    // Validação básica de CPF
    if (/^(\d)\1{10}$/.test(cpfClean)) return false

    let sum = 0
    for (let i = 0; i < 9; i++) {
      sum += parseInt(cpfClean[i]) * (10 - i)
    }
    let digit = (sum * 10) % 11
    if (digit === 10) digit = 0
    if (digit !== parseInt(cpfClean[9])) return false

    sum = 0
    for (let i = 0; i < 10; i++) {
      sum += parseInt(cpfClean[i]) * (11 - i)
    }
    digit = (sum * 10) % 11
    if (digit === 10) digit = 0
    return digit === parseInt(cpfClean[10])
  },
  message,
})

export const cnpj = (message = 'CNPJ invalido'): ValidationRule => ({
  validate: (value) => {
    if (!value || typeof value !== 'string') return false
    const cnpjClean = value.replace(/\D/g, '')
    if (cnpjClean.length !== 14) return false

    // Validação básica de CNPJ
    if (/^(\d)\1{13}$/.test(cnpjClean)) return false

    const weights1 = [5, 4, 3, 2, 9, 8, 7, 6, 5, 4, 3, 2]
    const weights2 = [6, 5, 4, 3, 2, 9, 8, 7, 6, 5, 4, 3, 2]

    let sum = 0
    for (let i = 0; i < 12; i++) {
      sum += parseInt(cnpjClean[i]) * weights1[i]
    }
    let digit = sum % 11 < 2 ? 0 : 11 - (sum % 11)
    if (digit !== parseInt(cnpjClean[12])) return false

    sum = 0
    for (let i = 0; i < 13; i++) {
      sum += parseInt(cnpjClean[i]) * weights2[i]
    }
    digit = sum % 11 < 2 ? 0 : 11 - (sum % 11)
    return digit === parseInt(cnpjClean[13])
  },
  message,
})

export const cpfOrCnpj = (message = 'CPF ou CNPJ invalido'): ValidationRule => ({
  validate: (value) => {
    if (!value || typeof value !== 'string') return false
    const clean = value.replace(/\D/g, '')
    if (clean.length === 11) return cpf().validate(value)
    if (clean.length === 14) return cnpj().validate(value)
    return false
  },
  message,
})

export const phone = (message = 'Telefone invalido'): ValidationRule => ({
  validate: (value) => {
    if (!value || typeof value !== 'string') return false
    const phoneClean = value.replace(/\D/g, '')
    return phoneClean.length >= 10 && phoneClean.length <= 11
  },
  message,
})

export const cep = (message = 'CEP invalido'): ValidationRule => ({
  validate: (value) => {
    if (!value || typeof value !== 'string') return false
    const cepClean = value.replace(/\D/g, '')
    return cepClean.length === 8
  },
  message,
})

export const date = (message = 'Data invalida'): ValidationRule => ({
  validate: (value) => {
    if (!value || typeof value !== 'string') return false
    const dateObj = new Date(value)
    return !isNaN(dateObj.getTime())
  },
  message,
})

export const futureDate = (message = 'A data deve ser futura'): ValidationRule => ({
  validate: (value) => {
    if (!value || typeof value !== 'string') return false
    const dateObj = new Date(value)
    const today = new Date()
    today.setHours(0, 0, 0, 0)
    return dateObj >= today
  },
  message,
})

export const pattern = (regex: RegExp, message: string): ValidationRule => ({
  validate: (value) => typeof value === 'string' && regex.test(value),
  message,
})

// ===== FUNÇÃO DE VALIDAÇÃO =====

export function validate<T extends Record>(
  data: T,
  rules: Partial<Record>
): ValidationResult {
  const errors: ValidationError[] = []

  for (const [field, fieldRules] of Object.entries(rules)) {
    if (!fieldRules) continue

    const value = data[field]

    for (const rule of fieldRules as ValidationRule[]) {
      if (!rule.validate(value as string, data)) {
        errors.push({ field, message: rule.message })
        break // Stop at first error for this field
      }
    }
  }

  return {
    isValid: errors.length === 0,
    errors,
  }
}

// ===== VALIDAÇÕES DE FORMULÁRIOS =====

export const cadastroValidationRules = {
  nome: [required(), minLength(3, 'Nome deve ter pelo menos 3 caracteres')],
  cpfCnpj: [required(), cpfOrCnpj()],
  email: [required(), email()],
  telefone: [required(), phone()],
  cep: [required(), cep()],
  logradouro: [required()],
  numero: [required()],
  bairro: [required()],
  cidade: [required()],
  uf: [required()],
}

export const solicitacaoValidationRules = {
  titulo: [required(), minLength(5, 'Titulo deve ter pelo menos 5 caracteres')],
  descricao: [required(), minLength(10, 'Descricao deve ter pelo menos 10 caracteres')],
  tipo: [required()],
  prioridade: [required()],
}

export const documentoValidationRules = {
  tipo: [required()],
  titulo: [required(), minLength(3, 'Titulo deve ter pelo menos 3 caracteres')],
  destinatario: [required()],
  remetente: [required()],
  assunto: [required()],
  conteudo: [required(), minLength(10, 'Conteudo deve ter pelo menos 10 caracteres')],
}

// ===== MÁSCARAS =====

export function maskCPF(value: string): string {
  return value
    .replace(/\D/g, '')
    .replace(/(\d{3})(\d)/, '$1.$2')
    .replace(/(\d{3})(\d)/, '$1.$2')
    .replace(/(\d{3})(\d{1,2})/, '$1-$2')
    .replace(/(-\d{2})\d+?$/, '$1')
}

export function maskCNPJ(value: string): string {
  return value
    .replace(/\D/g, '')
    .replace(/(\d{2})(\d)/, '$1.$2')
    .replace(/(\d{3})(\d)/, '$1.$2')
    .replace(/(\d{3})(\d)/, '$1/$2')
    .replace(/(\d{4})(\d)/, '$1-$2')
    .replace(/(-\d{2})\d+?$/, '$1')
}

export function maskCPFOrCNPJ(value: string): string {
  const clean = value.replace(/\D/g, '')
  if (clean.length <= 11) return maskCPF(value)
  return maskCNPJ(value)
}

export function maskPhone(value: string): string {
  return value
    .replace(/\D/g, '')
    .replace(/(\d{2})(\d)/, '($1) $2')
    .replace(/(\d{5})(\d)/, '$1-$2')
    .replace(/(-\d{4})\d+?$/, '$1')
}

export function maskCEP(value: string): string {
  return value
    .replace(/\D/g, '')
    .replace(/(\d{5})(\d)/, '$1-$2')
    .replace(/(-\d{3})\d+?$/, '$1')
}





























/**
 * Helpers para localStorage com tratamento de erros
 */

export function storageGet(key: string, defaultValue: T): T {
  if (typeof window === 'undefined') return defaultValue

  try {
    const item = localStorage.getItem(key)
    if (!item) return defaultValue
    return JSON.parse(item) as T
  } catch (error) {
    console.error(`Erro ao ler ${key} do localStorage:`, error)
    return defaultValue
  }
}

export function storageSet(key: string, value: T): boolean {
  if (typeof window === 'undefined') return false

  try {
    localStorage.setItem(key, JSON.stringify(value))
    return true
  } catch (error) {
    console.error(`Erro ao salvar ${key} no localStorage:`, error)
    return false
  }
}

export function storageRemove(key: string): boolean {
  if (typeof window === 'undefined') return false

  try {
    localStorage.removeItem(key)
    return true
  } catch (error) {
    console.error(`Erro ao remover ${key} do localStorage:`, error)
    return false
  }
}

export function storageClear(): boolean {
  if (typeof window === 'undefined') return false

  try {
    localStorage.clear()
    return true
  } catch (error) {
    console.error('Erro ao limpar localStorage:', error)
    return false
  }
}

/**
 * CRUD genérico para localStorage
 */
export function createStorageCRUD(storageKey: string) {
  return {
    getAll: (): T[] => storageGet(storageKey, []),

    getById: (id: string): T | undefined => {
      const items = storageGet(storageKey, [])
      return items.find((item) => item.id === id)
    },

    create: (item: T): T => {
      const items = storageGet(storageKey, [])
      items.push(item)
      storageSet(storageKey, items)
      return item
    },

    update: (id: string, updates: Partial): T | undefined => {
      const items = storageGet(storageKey, [])
      const index = items.findIndex((item) => item.id === id)
      if (index === -1) return undefined

      items[index] = { ...items[index], ...updates }
      storageSet(storageKey, items)
      return items[index]
    },

    delete: (id: string): boolean => {
      const items = storageGet(storageKey, [])
      const filtered = items.filter((item) => item.id !== id)
      if (filtered.length === items.length) return false

      storageSet(storageKey, filtered)
      return true
    },

    deleteAll: (): boolean => {
      return storageRemove(storageKey)
    },
  }
}



import { create } from 'zustand'
import { persist } from 'zustand/middleware'
import type { 
  AppState, 
  Cadastro, 
  CadastroForm,
  Solicitacao, 
  SolicitacaoForm,
  Documento,
  DocumentoForm,
  ConfiguracoesApp 
} from '@/lib/types'
import { 
  MOCK_CADASTROS, 
  MOCK_SOLICITACOES, 
  MOCK_DOCUMENTOS,
  DEFAULT_CONFIGURACOES 
} from '@/lib/constants'

// Gerar ID único
function generateId(): string {
  return `${Date.now()}-${Math.random().toString(36).substring(2, 9)}`
}

// Data atual ISO
function now(): string {
  return new Date().toISOString()
}

interface AppStore extends AppState {
  // Cadastros
  addCadastro: (data: CadastroForm) => Cadastro
  updateCadastro: (id: string, data: Partial) => void
  deleteCadastro: (id: string) => void

  // Solicitações
  addSolicitacao: (data: SolicitacaoForm) => Solicitacao
  updateSolicitacao: (id: string, data: Partial) => void
  deleteSolicitacao: (id: string) => void

  // Documentos
  addDocumento: (data: DocumentoForm) => Documento
  updateDocumento: (id: string, data: Partial) => void
  deleteDocumento: (id: string) => void

  // Configurações
  updateConfiguracoes: (data: Partial) => void

  // UI
  toggleSidebar: () => void
  setSidebarCollapsed: (collapsed: boolean) => void

  // Rascunhos
  saveRascunhoCadastro: (data: Partial) => void
  clearRascunhoCadastro: () => void
  saveRascunhoSolicitacao: (data: Partial) => void
  clearRascunhoSolicitacao: () => void
  saveRascunhoDocumento: (data: Partial) => void
  clearRascunhoDocumento: () => void

  // Reset
  resetToMockData: () => void
}

const initialState: AppState = {
  cadastros: MOCK_CADASTROS,
  solicitacoes: MOCK_SOLICITACOES,
  documentos: MOCK_DOCUMENTOS,
  configuracoes: DEFAULT_CONFIGURACOES,
  sidebarCollapsed: false,
  rascunhos: {},
}

export const useAppStore = create()(
  persist(
    (set, get) => ({
      ...initialState,

      // ===== CADASTROS =====
      addCadastro: (data) => {
        const novoCadastro: Cadastro = {
          ...data,
          id: generateId(),
          criadoEm: now(),
          atualizadoEm: now(),
        }
        set((state) => ({
          cadastros: [...state.cadastros, novoCadastro],
        }))
        return novoCadastro
      },

      updateCadastro: (id, data) => {
        set((state) => ({
          cadastros: state.cadastros.map((c) =>
            c.id === id ? { ...c, ...data, atualizadoEm: now() } : c
          ),
        }))
      },

      deleteCadastro: (id) => {
        set((state) => ({
          cadastros: state.cadastros.filter((c) => c.id !== id),
        }))
      },

      // ===== SOLICITAÇÕES =====
      addSolicitacao: (data) => {
        const novaSolicitacao: Solicitacao = {
          ...data,
          id: generateId(),
          criadoEm: now(),
          atualizadoEm: now(),
        }
        set((state) => ({
          solicitacoes: [...state.solicitacoes, novaSolicitacao],
        }))
        return novaSolicitacao
      },

      updateSolicitacao: (id, data) => {
        set((state) => ({
          solicitacoes: state.solicitacoes.map((s) =>
            s.id === id ? { ...s, ...data, atualizadoEm: now() } : s
          ),
        }))
      },

      deleteSolicitacao: (id) => {
        set((state) => ({
          solicitacoes: state.solicitacoes.filter((s) => s.id !== id),
        }))
      },

      // ===== DOCUMENTOS =====
      addDocumento: (data) => {
        const novoDocumento: Documento = {
          ...data,
          id: generateId(),
          criadoEm: now(),
          atualizadoEm: now(),
        }
        set((state) => ({
          documentos: [...state.documentos, novoDocumento],
        }))
        return novoDocumento
      },

      updateDocumento: (id, data) => {
        set((state) => ({
          documentos: state.documentos.map((d) =>
            d.id === id ? { ...d, ...data, atualizadoEm: now() } : d
          ),
        }))
      },

      deleteDocumento: (id) => {
        set((state) => ({
          documentos: state.documentos.filter((d) => d.id !== id),
        }))
      },

      // ===== CONFIGURAÇÕES =====
      updateConfiguracoes: (data) => {
        set((state) => ({
          configuracoes: {
            ...state.configuracoes,
            ...data,
            perfil: data.perfil 
              ? { ...state.configuracoes.perfil, ...data.perfil }
              : state.configuracoes.perfil,
            notificacoes: data.notificacoes
              ? { ...state.configuracoes.notificacoes, ...data.notificacoes }
              : state.configuracoes.notificacoes,
          },
        }))
      },

      // ===== UI =====
      toggleSidebar: () => {
        set((state) => ({
          sidebarCollapsed: !state.sidebarCollapsed,
        }))
      },

      setSidebarCollapsed: (collapsed) => {
        set({ sidebarCollapsed: collapsed })
      },

      // ===== RASCUNHOS =====
      saveRascunhoCadastro: (data) => {
        set((state) => ({
          rascunhos: { ...state.rascunhos, cadastro: data },
        }))
      },

      clearRascunhoCadastro: () => {
        set((state) => ({
          rascunhos: { ...state.rascunhos, cadastro: undefined },
        }))
      },

      saveRascunhoSolicitacao: (data) => {
        set((state) => ({
          rascunhos: { ...state.rascunhos, solicitacao: data },
        }))
      },

      clearRascunhoSolicitacao: () => {
        set((state) => ({
          rascunhos: { ...state.rascunhos, solicitacao: undefined },
        }))
      },

      saveRascunhoDocumento: (data) => {
        set((state) => ({
          rascunhos: { ...state.rascunhos, documento: data },
        }))
      },

      clearRascunhoDocumento: () => {
        set((state) => ({
          rascunhos: { ...state.rascunhos, documento: undefined },
        }))
      },

      // ===== RESET =====
      resetToMockData: () => {
        set(initialState)
      },
    }),
    {
      name: 'sistema-interno-storage',
      partialize: (state) => ({
        cadastros: state.cadastros,
        solicitacoes: state.solicitacoes,
        documentos: state.documentos,
        configuracoes: state.configuracoes,
        rascunhos: state.rascunhos,
      }),
    }
  )
)

// Seletores para uso otimizado
export const useCadastros = () => useAppStore((state) => state.cadastros)
export const useSolicitacoes = () => useAppStore((state) => state.solicitacoes)
export const useDocumentos = () => useAppStore((state) => state.documentos)
export const useConfiguracoes = () => useAppStore((state) => state.configuracoes)
export const useSidebarCollapsed = () => useAppStore((state) => state.sidebarCollapsed)
export const useRascunhos = () => useAppStore((state) => state.rascunhos)



