@import 'tailwindcss';
@import 'tw-animate-css';

@custom-variant dark (&:is(.dark *));

:root {
  /* Tema Institucional Neutro - baseado no Gerador de Oficios */
  /* Fundo: slate-50 (#f8fafc) */
  --background: oklch(0.984 0.003 247);
  /* Texto: slate-700 (#334155) */
  --foreground: oklch(0.446 0.03 256);
  /* Cards: branco puro */
  --card: oklch(1 0 0);
  --card-foreground: oklch(0.446 0.03 256);
  --popover: oklch(1 0 0);
  --popover-foreground: oklch(0.446 0.03 256);
  /* Primary: slate-700/800 - azul escuro institucional */
  --primary: oklch(0.372 0.044 257);
  --primary-foreground: oklch(1 0 0);
  /* Secondary: slate-100 */
  --secondary: oklch(0.968 0.003 264);
  --secondary-foreground: oklch(0.446 0.03 256);
  /* Muted: slate-100/50 */
  --muted: oklch(0.968 0.003 264);
  --muted-foreground: oklch(0.554 0.022 257);
  /* Accent: slate-100 */
  --accent: oklch(0.968 0.003 264);
  --accent-foreground: oklch(0.372 0.044 257);
  /* Destructive: red-600 */
  --destructive: oklch(0.577 0.245 27);
  --destructive-foreground: oklch(1 0 0);
  /* Border: slate-200 */
  --border: oklch(0.929 0.006 264);
  /* Input: slate-200 */
  --input: oklch(0.929 0.006 264);
  /* Ring: slate-400 */
  --ring: oklch(0.704 0.022 261);
  /* Charts - tons de slate/azul */
  --chart-1: oklch(0.372 0.044 257);
  --chart-2: oklch(0.554 0.022 257);
  --chart-3: oklch(0.704 0.022 261);
  --chart-4: oklch(0.446 0.03 256);
  --chart-5: oklch(0.60 0.10 250);
  --radius: 0.5rem;

  /* Sidebar */
  --sidebar: oklch(1 0 0);
  --sidebar-foreground: oklch(0.446 0.03 256);
  --sidebar-primary: oklch(0.372 0.044 257);
  --sidebar-primary-foreground: oklch(1 0 0);
  --sidebar-accent: oklch(0.968 0.003 264);
  --sidebar-accent-foreground: oklch(0.372 0.044 257);
  --sidebar-border: oklch(0.929 0.006 264);
  --sidebar-ring: oklch(0.704 0.022 261);

  /* Fundo da pagina: cinza muito claro */
  --gradient-page: oklch(0.984 0.003 247);

  /* Cores de status */
  --success: oklch(0.65 0.18 145);
  --success-foreground: oklch(1 0 0);
  --warning: oklch(0.75 0.15 85);
  --warning-foreground: oklch(0.3 0.05 85);
  --info: oklch(0.6 0.10 250);
  --info-foreground: oklch(1 0 0);
}

.dark {
  /* Dark mode - slate tones */
  --background: oklch(0.129 0.015 264);
  --foreground: oklch(0.968 0.003 264);
  --card: oklch(0.178 0.015 264);
  --card-foreground: oklch(0.968 0.003 264);
  --popover: oklch(0.178 0.015 264);
  --popover-foreground: oklch(0.968 0.003 264);
  --primary: oklch(0.704 0.022 261);
  --primary-foreground: oklch(0.129 0.015 264);
  --secondary: oklch(0.227 0.018 264);
  --secondary-foreground: oklch(0.929 0.006 264);
  --muted: oklch(0.227 0.018 264);
  --muted-foreground: oklch(0.704 0.022 261);
  --accent: oklch(0.279 0.021 264);
  --accent-foreground: oklch(0.929 0.006 264);
  --destructive: oklch(0.50 0.20 27);
  --destructive-foreground: oklch(0.968 0.003 264);
  --border: oklch(0.279 0.021 264);
  --input: oklch(0.279 0.021 264);
  --ring: oklch(0.554 0.022 257);
  --chart-1: oklch(0.704 0.022 261);
  --chart-2: oklch(0.554 0.022 257);
  --chart-3: oklch(0.446 0.03 256);
  --chart-4: oklch(0.60 0.10 250);
  --chart-5: oklch(0.65 0.08 260);

  /* Sidebar dark */
  --sidebar: oklch(0.178 0.015 264);
  --sidebar-foreground: oklch(0.968 0.003 264);
  --sidebar-primary: oklch(0.704 0.022 261);
  --sidebar-primary-foreground: oklch(0.129 0.015 264);
  --sidebar-accent: oklch(0.279 0.021 264);
  --sidebar-accent-foreground: oklch(0.929 0.006 264);
  --sidebar-border: oklch(0.279 0.021 264);
  --sidebar-ring: oklch(0.554 0.022 257);

  /* Background dark */
  --gradient-page: oklch(0.129 0.015 264);

  /* Cores de status dark */
  --success: oklch(0.55 0.15 145);
  --success-foreground: oklch(0.95 0 0);
  --warning: oklch(0.65 0.12 85);
  --warning-foreground: oklch(0.2 0.02 85);
  --info: oklch(0.55 0.10 250);
  --info-foreground: oklch(0.95 0 0);
}

@theme inline {
  --font-sans: 'Geist', 'Geist Fallback';
  --font-mono: 'Geist Mono', 'Geist Mono Fallback';
  --color-background: var(--background);
  --color-foreground: var(--foreground);
  --color-card: var(--card);
  --color-card-foreground: var(--card-foreground);
  --color-popover: var(--popover);
  --color-popover-foreground: var(--popover-foreground);
  --color-primary: var(--primary);
  --color-primary-foreground: var(--primary-foreground);
  --color-secondary: var(--secondary);
  --color-secondary-foreground: var(--secondary-foreground);
  --color-muted: var(--muted);
  --color-muted-foreground: var(--muted-foreground);
  --color-accent: var(--accent);
  --color-accent-foreground: var(--accent-foreground);
  --color-destructive: var(--destructive);
  --color-destructive-foreground: var(--destructive-foreground);
  --color-border: var(--border);
  --color-input: var(--input);
  --color-ring: var(--ring);
  --color-chart-1: var(--chart-1);
  --color-chart-2: var(--chart-2);
  --color-chart-3: var(--chart-3);
  --color-chart-4: var(--chart-4);
  --color-chart-5: var(--chart-5);
  --radius-sm: calc(var(--radius) - 4px);
  --radius-md: calc(var(--radius) - 2px);
  --radius-lg: var(--radius);
  --radius-xl: calc(var(--radius) + 4px);
  --color-sidebar: var(--sidebar);
  --color-sidebar-foreground: var(--sidebar-foreground);
  --color-sidebar-primary: var(--sidebar-primary);
  --color-sidebar-primary-foreground: var(--sidebar-primary-foreground);
  --color-sidebar-accent: var(--sidebar-accent);
  --color-sidebar-accent-foreground: var(--sidebar-accent-foreground);
  --color-sidebar-border: var(--sidebar-border);
  --color-sidebar-ring: var(--sidebar-ring);
}

@layer base {
  * {
    @apply border-border outline-ring/50;
  }
  body {
    @apply bg-background text-foreground;
  }
}

/* Animações customizadas */
@keyframes subtle-pulse {
  0%, 100% { opacity: 1; }
  50% { opacity: 0.7; }
}

@keyframes fade-in-slide-up {
  from {
    opacity: 0;
    transform: translateY(8px);
  }
  to {
    opacity: 1;
    transform: translateY(0);
  }
}

@keyframes fade-in {
  from { opacity: 0; }
  to { opacity: 1; }
}

@keyframes spin-slow {
  from { transform: rotate(0deg); }
  to { transform: rotate(360deg); }
}

.animate-subtle-pulse {
  animation: subtle-pulse 2s ease-in-out infinite;
}

.animate-fade-in-slide-up {
  animation: fade-in-slide-up 0.3s ease-out forwards;
}

.animate-fade-in {
  animation: fade-in 0.2s ease-out forwards;
}

.animate-spin-slow {
  animation: spin-slow 1.5s linear infinite;
}

/* Fundo da pagina */
.bg-gradient-page {
  background-color: var(--gradient-page);
}

/* Estilos para formulários */
.form-input-focus {
  @apply focus:ring-2 focus:ring-primary/20 focus:border-primary transition-all duration-200;
}

/* Estilo de documento/preview (fonte serif) */
.document-text {
  font-family: 'Source Serif 4', 'Georgia', serif;
}

/* Scrollbar customizada */
.scrollbar-thin {
  scrollbar-width: thin;
  scrollbar-color: var(--border) transparent;
}

.scrollbar-thin::-webkit-scrollbar {
  width: 6px;
  height: 6px;
}

.scrollbar-thin::-webkit-scrollbar-track {
  background: transparent;
}

.scrollbar-thin::-webkit-scrollbar-thumb {
  background: var(--border);
  border-radius: 3px;
}

.scrollbar-thin::-webkit-scrollbar-thumb:hover {
  background: var(--muted-foreground);
}



'use client'

import { forwardRef } from 'react'
import { cn } from '@/lib/utils'
import { Input } from '@/components/ui/input'
import { Textarea } from '@/components/ui/textarea'
import { Label } from '@/components/ui/label'
import {
  Select,
  SelectContent,
  SelectItem,
  SelectTrigger,
  SelectValue,
} from '@/components/ui/select'

interface BaseFieldProps {
  label: string
  name: string
  error?: string
  required?: boolean
  hint?: string
  className?: string
}

interface InputFieldProps extends BaseFieldProps {
  type: 'text' | 'email' | 'tel' | 'password' | 'number' | 'date' | 'url'
  value: string
  onChange: (value: string) => void
  onBlur?: () => void
  placeholder?: string
  disabled?: boolean
  mask?: (value: string) => string
}

interface TextareaFieldProps extends BaseFieldProps {
  type: 'textarea'
  value: string
  onChange: (value: string) => void
  onBlur?: () => void
  placeholder?: string
  disabled?: boolean
  rows?: number
}

interface SelectOption {
  value: string
  label: string
}

interface SelectFieldProps extends BaseFieldProps {
  type: 'select'
  value: string
  onChange: (value: string) => void
  onBlur?: () => void
  options: SelectOption[]
  placeholder?: string
  disabled?: boolean
}

type FormFieldProps = InputFieldProps | TextareaFieldProps | SelectFieldProps

export const FormField = forwardRef(
  (props, ref) => {
    const { label, name, error, required, hint, className } = props

    const fieldId = `field-${name}`
    const errorId = `${fieldId}-error`
    const hintId = `${fieldId}-hint`

    return (



          {label}
          {required && (

              *

          )}


        {props.type === 'textarea' ? (
          <Textarea
            ref={ref as React.Ref}
            id={fieldId}
            name={name}
            value={props.value}
            onChange={(e) => props.onChange(e.target.value)}
            onBlur={props.onBlur}
            placeholder={props.placeholder}
            disabled={props.disabled}
            rows={props.rows ?? 4}
            aria-required={required}
            aria-invalid={!!error}
            aria-describedby={error ? errorId : hint ? hintId : undefined}
            className={cn(
              'resize-none form-input-focus',
              error && 'border-destructive focus:ring-destructive/20'
            )}
          />
        ) : props.type === 'select' ? (





              {props.options.map((option) => (

                  {option.label}

              ))}


        ) : (
          <Input
            ref={ref as React.Ref}
            id={fieldId}
            name={name}
            type={props.type}
            value={props.value}
            onChange={(e) => {
              const value = props.mask ? props.mask(e.target.value) : e.target.value
              props.onChange(value)
            }}
            onBlur={props.onBlur}
            placeholder={props.placeholder}
            disabled={props.disabled}
            aria-required={required}
            aria-invalid={!!error}
            aria-describedby={error ? errorId : hint ? hintId : undefined}
            className={cn(
              'form-input-focus',
              error && 'border-destructive focus:ring-destructive/20'
            )}
          />
        )}

        {error && (


            {error}

        )}

        {hint && !error && (


            {hint}

        )}

    )
  }
)

FormField.displayName = 'FormField'



