                />
                 handleFieldChange('complemento', v)}
                  placeholder="Apto, Sala, etc."
                />
                 handleFieldChange('bairro', v)}
                  onBlur={() => handleFieldBlur('bairro')}
                  error={getFieldError('bairro')}
                  required
                  placeholder="Nome do bairro"
                />
                 handleFieldChange('cidade', v)}
                  onBlur={() => handleFieldBlur('cidade')}
                  error={getFieldError('cidade')}
                  required
                  placeholder="Nome da cidade"
                />
                 handleFieldChange('uf', v)}
                  onBlur={() => handleFieldBlur('uf')}
                  error={getFieldError('uf')}
                  options={UF_OPTIONS}
                  required
                  placeholder="Selecione o estado"
                />
                 handleFieldChange('status', v as 'ativo' | 'inativo' | 'pendente')}
                  options={[
                    { value: 'ativo', label: 'Ativo' },
                    { value: 'inativo', label: 'Inativo' },
                    { value: 'pendente', label: 'Pendente' },
                  ]}
                />




              {/* Observacoes */}

                 handleFieldChange('observacoes', v)}
                  placeholder="Digite observações adicionais..."
                  rows={3}
                  className="sm:col-span-2"
                />







        {/* Saved Items List */}



            {cadastros.length === 0 ? (




            ) : (



                  {cadastros.map((cadastro) => (

 handleSelectCadastro(cadastro)}
                    >



{cadastro.nome}

{cadastro.email}




                         {
                            e.stopPropagation()
                            handleDelete(cadastro.id)
                          }}
                        >




