import { Card, CardContent, CardDescription, CardHeader, CardTitle } from '@/components/ui/card'

interface SectionCardProps {
  title?: string
  description?: string
  actions?: ReactNode
  children: ReactNode
  className?: string
  contentClassName?: string
  noPadding?: boolean
}

export function SectionCard({ 
  title, 
  description, 
  actions,
  children, 
  className,
  contentClassName,
  noPadding = false,
}: SectionCardProps) {
  const hasHeader = title || description || actions

  return (

      {hasHeader && (



            {title && {title}}
            {description && {description}}

          {actions && (


              {actions}

          )}

      )}

        {children}


  )
}
